#include "kernel_operator.h"

class KernelConvPointwise2dCustom {
public:
    __aicore__ inline KernelConvPointwise2dCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR w, GM_ADDR y,
                                uint32_t N, uint32_t C_in, uint32_t H, uint32_t W, uint32_t C_out,
                                uint32_t tilePixels, uint32_t tileCout)
    {
        N_ = N;
        Cin_ = C_in;
        H_ = H;
        W_ = W;
        Cout_ = C_out;
        S_ = H_ * W_;
        tilePixels_ = tilePixels;
        tileCout_ = tileCout;

        xGm_.SetGlobalBuffer((__gm__ float*)x, static_cast<uint64_t>(N_) * Cin_ * S_);
        wGm_.SetGlobalBuffer((__gm__ float*)w, static_cast<uint64_t>(Cout_) * Cin_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, static_cast<uint64_t>(N_) * Cout_ * S_);

        pipe_.InitBuffer(xVecQ_, 1, tilePixels_ * sizeof(float));
        pipe_.InitBuffer(tmpVecQ_, 1, tilePixels_ * sizeof(float));
        pipe_.InitBuffer(wSubQ_, 1, tileCout_ * Cin_ * sizeof(float));
        pipe_.InitBuffer(yTileQ_, 1, tileCout_ * tilePixels_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (N_ == 0 || Cin_ == 0 || Cout_ == 0 || S_ == 0 || tilePixels_ == 0 || tileCout_ == 0) {
            return;
        }

        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        if (blockIdx >= N_) return;
        const uint32_t n = blockIdx;

        const uint32_t numOCChunks = (Cout_ + tileCout_ - 1u) / tileCout_;
        for (uint32_t ocChunk = 0; ocChunk < numOCChunks; ++ocChunk) {
            const uint32_t ocStart = ocChunk * tileCout_;
            const uint32_t coCurr = (ocStart + tileCout_ <= Cout_) ? tileCout_ : (Cout_ - ocStart);

            // Load weight submatrix [coCurr x Cin_] contiguous
            AscendC::LocalTensor<float> wSubLocal = wSubQ_.AllocTensor<float>();
            const uint32_t wElems = coCurr * Cin_;
            AscendC::DataCopy(wSubLocal, wGm_[ocStart * Cin_], wElems);

            // Iterate over spatial tiles
            for (uint32_t pStart = 0; pStart < S_; pStart += tilePixels_) {
                const uint32_t curP = ((pStart + tilePixels_) <= S_) ? tilePixels_ : (S_ - pStart);

                AscendC::LocalTensor<float> yTileLocal = yTileQ_.AllocTensor<float>();

                // Compute y = sum_c x * w for this (n, oc range, p range)
                for (uint32_t c = 0; c < Cin_; ++c) {
                    // Load x vector [curP] for (n, c, p range)
                    const uint64_t xBase = static_cast<uint64_t>((n * Cin_ + c)) * S_ + pStart;
                    AscendC::LocalTensor<float> xLocal = xVecQ_.AllocTensor<float>();
                    AscendC::DataCopy(xLocal, xGm_[xBase], curP);

                    if (c == 0) {
                        // First channel initializes y columns: y_col = x * w
                        for (uint32_t oc = 0; oc < coCurr; ++oc) {
                            const uint32_t yOff = oc * tilePixels_;
                            // weight scalar w[oc, c]
                            float wScalar = wSubLocal.GetValue(oc * Cin_ + c);
                            AscendC::Muls(yTileLocal[yOff], xLocal, wScalar, curP);
                        }
                    } else {
                        // Accumulate: y_col += x * w
                        AscendC::LocalTensor<float> tmpLocal = tmpVecQ_.AllocTensor<float>();
                        for (uint32_t oc = 0; oc < coCurr; ++oc) {
                            const uint32_t yOff = oc * tilePixels_;
                            float wScalar = wSubLocal.GetValue(oc * Cin_ + c);
                            AscendC::Muls(tmpLocal, xLocal, wScalar, curP);
                            AscendC::Add(yTileLocal[yOff], yTileLocal[yOff], tmpLocal, curP);
                        }
                        tmpVecQ_.FreeTensor(tmpLocal);
                    }

                    xVecQ_.FreeTensor(xLocal);
                }

                // Store yTile to GM for each oc in the chunk
                for (uint32_t oc = 0; oc < coCurr; ++oc) {
                    const uint64_t yBase = static_cast<uint64_t>((n * Cout_ + (ocStart + oc))) * S_ + pStart;
                    AscendC::DataCopy(yGm_[yBase], yTileLocal[oc * tilePixels_], curP);
                }

                yTileQ_.FreeTensor(yTileLocal);
            }

            wSubQ_.FreeTensor(wSubLocal);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> xVecQ_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpVecQ_;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> wSubQ_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> yTileQ_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t N_{0};
    uint32_t Cin_{0};
    uint32_t H_{0};
    uint32_t W_{0};
    uint32_t Cout_{0};
    uint32_t S_{0};
    uint32_t tilePixels_{0};
    uint32_t tileCout_{0};
};

extern "C" __global__ __aicore__ void conv_pointwise_2d_custom(GM_ADDR x, GM_ADDR weight, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelConvPointwise2dCustom op;
    op.Init(x, weight, y,
            tiling_data.n, tiling_data.cIn, tiling_data.h, tiling_data.w, tiling_data.cOut,
            tiling_data.tilePixels, tiling_data.tileCout);
    op.Process();
}
